// PROP-009 precondition: pop ONLY if a review file has matching queue_id (strict)
// OR its target_id substring-matches AND reviewed_at > pushed_at (soft fallback).
// Neither? Leave item in place. Prevents pre-existing old reviews from
// substring-matching a freshly pushed post-integration re-review item.
const fs=require('fs');
const path=require('path');
const CLONE='${CLEAN_CLONE}';
const WORKSPACE=process.cwd(); // FUSE workspace — where curmudgeon writes reviews
const pq=JSON.parse(fs.readFileSync(CLONE+'/monitor/curmudgeon/priority-queue.json','utf8'));
const reviewsDir=WORKSPACE+'/monitor/curmudgeon/reviews/';
const reviewFiles=fs.readdirSync(reviewsDir).filter(f=>f.endsWith('.json'));
// Pre-parse every review once (50-200 files, cheap)
const reviewsMeta=reviewFiles.map(f=>{
  try{
    const d=JSON.parse(fs.readFileSync(path.join(reviewsDir,f),'utf8'));
    return {file:f, queue_id:d.queue_id||d.priority_queue_id||null, reviewed_at:d.reviewed_at||null};
  }catch(e){return {file:f, queue_id:null, reviewed_at:null};}
});
const shadow=[]; // track would-have-popped items for migration audit (Phase A)
const enforce=${PROP_009_ENFORCE:-false}; // flip to true after shadow period
const before=pq.queue.length;
if(!pq.history) pq.history=[];
pq.queue=pq.queue.filter(item=>{
  const tid=item.target_id;
  const secMatch=tid.match(/^part(\\d+[a-z]?)-(.+)$/);
  const searchTerms=[tid]; if(secMatch) searchTerms.push('SEC-'+secMatch[2]);
  // Legacy substring match (what the old code did — used only for backward-compat)
  const legacyMatch=reviewsMeta.some(r=>searchTerms.some(t=>r.file.includes(t)));
  // Strict: queue_id match
  const strictMatch=reviewsMeta.some(r=>r.queue_id===item.queue_id);
  // Soft fallback: substring + reviewed_at post-dates pushed_at
  const pushedAt=item.pushed_at?new Date(item.pushed_at).getTime():0;
  const softMatch=reviewsMeta.some(r=>{
    if(!searchTerms.some(t=>r.file.includes(t))) return false;
    if(!r.reviewed_at) return false;
    return new Date(r.reviewed_at).getTime()>pushedAt;
  });
  // Operator escape hatch (only when explicit opt-out)
  const operatorBypass=(item.require_matching_review_file===false) && (item.pushed_by||'').includes('operator');
  const shouldPop=strictMatch||softMatch||operatorBypass;
  if(shouldPop){
    pq.history.push({queue_id:item.queue_id,target_id:tid,target_type:item.target_type,popped_at:new Date().toISOString(),popped_by:'decider',pop_reason:strictMatch?'strict_queue_id':softMatch?'soft_reviewed_at_after_pushed_at':'operator_bypass'});
    return false;
  }
  if(legacyMatch && !shouldPop){
    // Shadow finding: would-have-popped under old rule. Log for migration audit.
    shadow.push({queue_id:item.queue_id,target_id:tid,pushed_at:item.pushed_at,would_have_popped_under:'legacy_substring',blocked_because:'no_strict_or_soft_match'});
    if(!enforce){
      // During shadow period, still pop so we don't create a backlog. Just log.
      pq.history.push({queue_id:item.queue_id,target_id:tid,target_type:item.target_type,popped_at:new Date().toISOString(),popped_by:'decider',pop_reason:'shadow_legacy_substring'});
      return false;
    }
    // Under enforcement, do NOT pop — leave the item in the queue for curmudgeon.
    return true;
  }
  // Stale-item escalation (applies under enforcement only)
  if(enforce && item.pushed_at){
    const ageDays=(Date.now()-new Date(item.pushed_at).getTime())/86400000;
    if(ageDays>7){
      console.log('STALE_QUEUE_ITEM: '+tid+' (qid '+item.queue_id+') unreviewed for '+ageDays.toFixed(1)+' days — escalate to tinker via attention-inbox, do NOT auto-pop');
    }
  }
  return true;
});
// Write shadow log for migration audit
if(shadow.length){
  const logPath=CLONE+'/monitor/integrity/prop-009-shadow.jsonl';
  fs.mkdirSync(path.dirname(logPath),{recursive:true});
  for(const s of shadow){s.logged_at=new Date().toISOString(); fs.appendFileSync(logPath,JSON.stringify(s)+'\\n');}
  console.log('PROP-009 shadow: '+shadow.length+' item(s) would have been blocked under enforcement');
}
if(pq.history.length>50) pq.history=pq.history.slice(-50);
const after=pq.queue.length;
fs.writeFileSync(CLONE+'/monitor/curmudgeon/priority-queue.json',JSON.stringify(pq,null,2));
if(before!==after){
  console.log('Popped '+(before-after)+' reviewed items. Queue: '+before+' -> '+after);
}else{
  console.log('No items to pop. Queue depth: '+after);
}
"
